// ─── WebSocket messages ───────────────────────────────────────────────────
// Not part of the REST OpenAPI spec — these describe WebSocket frame
// payloads, so there is no backend schema to alias.

export type WsMessageType = 'progress' | 'file_update' | 'complete' | 'error' | 'cancelled' | 'event'

export interface TaskEvent {
  ts: string
  level: 'info' | 'warn' | 'error'
  msg: string
  ctx?: Record<string, unknown>
}

export interface WsProgressData {
  current: number
  total: number
  message: string
}

export interface WsFileUpdateData {
  filename: string
  action: string
}

export interface WsCompleteData {
  summary: Record<string, unknown>
}

export interface WsErrorData {
  error: string
}

export type WsMessage =
  | { type: 'progress'; data: WsProgressData }
  | { type: 'file_update'; data: WsFileUpdateData }
  | { type: 'complete'; data: WsCompleteData }
  | { type: 'error'; data: WsErrorData }
  | { type: 'cancelled'; data: Record<string, never> }
  | { type: 'event'; data: TaskEvent }

